// ─── Publish Page ──────────────────────────────────────────────────────────
const PUB_STEPS = ["pub_step_basics", "pub_step_source", "pub_step_listing", "pub_step_review"];
const ICON_COLORS = {
  indigo: { bg:"oklch(58% 0.18 268)", fg:"#fff" },
  amber:  { bg:"oklch(72% 0.16 60)",  fg:"#1a1408" },
  emerald:{ bg:"oklch(62% 0.14 160)", fg:"#fff" },
  rose:   { bg:"oklch(64% 0.16 12)",  fg:"#fff" },
  slate:  { bg:"oklch(38% 0.02 260)", fg:"#fff" },
};

function PubField({ label, hint, required, optional, children }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
      <div style={{ display:"flex", alignItems:"baseline", gap:8 }}>
        <label style={{ fontSize:13, fontWeight:600 }}>{label}{required && <span style={{ color:"oklch(60% 0.18 28)", marginLeft:3 }}>*</span>}</label>
        {optional && <span style={{ fontSize:11, color:"#999", fontWeight:400 }}>{optional}</span>}
      </div>
      {children}
      {hint && <div style={{ fontSize:11.5, color:"#888", lineHeight:1.45 }}>{hint}</div>}
    </div>
  );
}

function PubInput({ value, onChange, placeholder, mono, theme, multiline, rows = 4 }) {
  const baseStyle = {
    width:"100%", padding:"9px 12px", borderRadius:8,
    border:`1px solid ${theme.cardBorder}`,
    background: theme.cardBg, color: theme.text,
    fontSize:13, fontFamily: mono ? "ui-monospace, SFMono-Regular, monospace" : "inherit",
    outline:"none", transition:"all 0.15s",
    boxSizing:"border-box", resize: multiline ? "vertical" : "none",
  };
  const onFocus = (e) => { e.target.style.borderColor = theme.accent; e.target.style.boxShadow = `0 0 0 3px ${theme.accent}1a`; };
  const onBlur = (e) => { e.target.style.borderColor = theme.cardBorder; e.target.style.boxShadow = "none"; };
  if (multiline) {
    return <textarea value={value} onChange={(e)=>onChange(e.target.value)} placeholder={placeholder} rows={rows} style={baseStyle} onFocus={onFocus} onBlur={onBlur}/>;
  }
  return <input type="text" value={value} onChange={(e)=>onChange(e.target.value)} placeholder={placeholder} style={baseStyle} onFocus={onFocus} onBlur={onBlur}/>;
}

function PubChoice({ value, current, onClick, title, desc, theme }) {
  const active = value === current;
  return (
    <button onClick={onClick} style={{
      textAlign:"left", padding:"12px 14px", borderRadius:10,
      border:`1.5px solid ${active ? theme.accent : theme.cardBorder}`,
      background: active ? `${theme.accent}0a` : theme.cardBg,
      cursor:"pointer", fontFamily:"inherit",
      transition:"all 0.18s",
      display:"flex", flexDirection:"column", gap:3,
    }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
        <span style={{ fontSize:13.5, fontWeight:600, color: theme.text }}>{title}</span>
        {active && <span style={{ width:16, height:16, borderRadius:"50%", background: theme.accent, display:"inline-flex", alignItems:"center", justifyContent:"center" }}><Icon name="check" size={10} color={theme.accentFg}/></span>}
      </div>
      <span style={{ fontSize:12, color: theme.textMuted, lineHeight:1.5 }}>{desc}</span>
    </button>
  );
}

// ─── Step content components ─────
function BasicsStep({ draft, setDraft, lang, t, theme }) {
  const update = (k, v) => setDraft(d => ({ ...d, [k]: v }));
  const slugFromName = (n) => n.toLowerCase().trim().replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,"").slice(0, 40);
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:22 }}>
      <PubField label={t.pub_name} hint={t.pub_name_hint} required>
        <PubInput value={draft.name} onChange={(v) => { update("name", v); if (!draft.slug || draft.slug === slugFromName(draft.name)) update("slug", slugFromName(v)); }} placeholder={t.pub_name_ph} theme={theme}/>
      </PubField>
      <PubField label={t.pub_slug} hint={t.pub_slug_hint} required>
        <PubInput value={draft.slug} onChange={(v)=>update("slug", v)} placeholder={t.pub_slug_ph} mono theme={theme}/>
      </PubField>
      <PubField label={t.pub_summary} required>
        <PubInput value={draft.summary} onChange={(v)=>update("summary", v)} placeholder={t.pub_summary_ph} theme={theme}/>
      </PubField>
      <PubField label={t.pub_type} required>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(4, 1fr)", gap:10 }}>
          {[
            { k:"skill",   label:t.pub_type_skill,   icon:"bolt" },
            { k:"mcp",     label:t.pub_type_mcp,     icon:"globe" },
            { k:"slash",   label:t.pub_type_slash,   icon:"command" },
            { k:"plugin",  label:t.pub_type_plugin,  icon:"plug" },
          ].map(opt => {
            const active = draft.type === opt.k;
            return (
              <button key={opt.k} onClick={()=>update("type", opt.k)} style={{
                display:"flex", flexDirection:"column", alignItems:"center", gap:6,
                padding:"14px 8px", borderRadius:10, fontFamily:"inherit", fontSize:12, fontWeight:600,
                border:`1.5px solid ${active ? theme.accent : theme.cardBorder}`,
                background: active ? `${theme.accent}0c` : theme.cardBg,
                color: active ? theme.accent : theme.text,
                cursor:"pointer", transition:"all 0.18s",
              }}>
                <Icon name={opt.icon} size={18} color={active ? theme.accent : theme.textMuted}/>
                <span>{opt.label}</span>
              </button>
            );
          })}
        </div>
      </PubField>
      <PubField label={t.pub_scope} required>
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          <PubChoice value="personal" current={draft.scope} onClick={()=>update("scope","personal")} title={t.pub_scope_personal_h} desc={t.pub_scope_personal_d} theme={theme}/>
          <PubChoice value="org" current={draft.scope} onClick={()=>update("scope","org")} title={t.pub_scope_org_h} desc={t.pub_scope_org_d} theme={theme}/>
          <PubChoice value="enterprise" current={draft.scope} onClick={()=>update("scope","enterprise")} title={t.pub_scope_enterprise_h} desc={t.pub_scope_enterprise_d} theme={theme}/>
        </div>
      </PubField>
    </div>
  );
}

function SourceStep({ draft, setDraft, lang, t, theme }) {
  const update = (k, v) => setDraft(d => ({ ...d, [k]: v }));
  const [copied, setCopied] = React.useState(null);
  const copy = (idx, text) => { navigator.clipboard?.writeText(text); setCopied(idx); setTimeout(()=>setCopied(null), 1500); };
  const cliCommands = [
    { label: t.pub_cli_step1, code: "npm install -g @agentcenter/cli" },
    { label: t.pub_cli_step2, code: "agentcenter login" },
    { label: t.pub_cli_step3, code: `agentcenter publish --slug ${draft.slug || "your-extension"}` },
  ];
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:22 }}>
      <PubField label={t.pub_source_method} required>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(3, 1fr)", gap:10 }}>
          {[
            { k:"zip", title:t.pub_source_zip, desc:t.pub_source_zip_d },
            { k:"git", title:t.pub_source_git, desc:t.pub_source_git_d },
            { k:"cli", title:t.pub_source_cli, desc:t.pub_source_cli_d },
          ].map(o => <PubChoice key={o.k} value={o.k} current={draft.sourceMethod} onClick={()=>update("sourceMethod", o.k)} title={o.title} desc={o.desc} theme={theme}/>)}
        </div>
      </PubField>

      {draft.sourceMethod === "zip" && (
        <div style={{
          border:`2px dashed ${draft.zipName ? theme.accent : theme.cardBorder}`,
          borderRadius:12, padding:"32px 20px",
          display:"flex", flexDirection:"column", alignItems:"center", gap:10,
          background: draft.zipName ? `${theme.accent}06` : "transparent",
          transition:"all 0.2s",
        }}>
          {draft.zipName ? (
            <>
              <Icon name="check" size={32} color={theme.accent}/>
              <div style={{ fontSize:14, fontWeight:600 }}>{draft.zipName}</div>
              <button onClick={()=>update("zipName","")} style={{ background:"none", border:"none", color: theme.textMuted, cursor:"pointer", fontSize:12, textDecoration:"underline" }}>{lang==="zh" ? "重新上传" : "Replace"}</button>
            </>
          ) : (
            <>
              <Icon name="upload" size={28} color={theme.textMuted}/>
              <div style={{ fontSize:14, fontWeight:600 }}>{t.pub_drop_here}</div>
              <button onClick={()=>update("zipName", "my-extension-v1.0.0.zip")} style={{ background: theme.accent, color: theme.accentFg, border:"none", borderRadius:7, padding:"8px 16px", fontFamily:"inherit", fontSize:12.5, fontWeight:600, cursor:"pointer" }}>{t.pub_or_browse}</button>
              <div style={{ fontSize:11.5, color:"#888", marginTop:4 }}>{t.pub_zip_hint}</div>
            </>
          )}
        </div>
      )}

      {draft.sourceMethod === "git" && (
        <div style={{ display:"flex", flexDirection:"column", gap:18 }}>
          <PubField label={t.pub_git_url} required>
            <PubInput value={draft.gitUrl} onChange={(v)=>update("gitUrl", v)} placeholder={t.pub_git_url_ph} mono theme={theme}/>
          </PubField>
          <PubField label={t.pub_git_branch} optional={t.pub_optional}>
            <PubInput value={draft.gitBranch} onChange={(v)=>update("gitBranch", v)} placeholder={t.pub_git_branch_ph} mono theme={theme}/>
          </PubField>
        </div>
      )}

      {draft.sourceMethod === "cli" && (
        <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
          {cliCommands.map((c, i) => (
            <div key={i}>
              <div style={{ fontSize:12, fontWeight:600, color: theme.textMuted, marginBottom:6 }}>{i+1}. {c.label}</div>
              <div style={{
                background: theme.contentBg, border:`1px solid ${theme.cardBorder}`,
                borderRadius:8, padding:"10px 12px",
                display:"flex", alignItems:"center", justifyContent:"space-between", gap:12,
                fontFamily:"ui-monospace, SFMono-Regular, monospace", fontSize:12.5,
              }}>
                <span style={{ color: theme.text, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>$ {c.code}</span>
                <button onClick={()=>copy(i, c.code)} style={{
                  background:"none", border:`1px solid ${theme.cardBorder}`, color: theme.textMuted,
                  padding:"3px 9px", borderRadius:5, fontSize:11, fontWeight:600, cursor:"pointer", fontFamily:"inherit",
                  display:"inline-flex", alignItems:"center", gap:4, flexShrink:0,
                }}>
                  {copied === i ? <><Icon name="check" size={11} color={theme.accent}/>{t.pub_copied}</> : <>{t.pub_copy}</>}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function ListingStep({ draft, setDraft, lang, t, theme }) {
  const update = (k, v) => setDraft(d => ({ ...d, [k]: v }));
  const [tagInput, setTagInput] = React.useState("");
  const [deptOpen, setDeptOpen] = React.useState(false);
  const addTag = () => {
    const v = tagInput.trim().toLowerCase();
    if (v && !draft.tags.includes(v)) update("tags", [...draft.tags, v]);
    setTagInput("");
  };
  const removeTag = (t) => update("tags", draft.tags.filter(x => x !== t));
  const suggestedTags = ["stable","beta","official","ai","search","data","productivity"].filter(x => !draft.tags.includes(x));
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:22 }}>
      <PubField label={t.pub_icon} hint={t.pub_icon_hint} optional={t.pub_optional}>
        <div style={{ display:"flex", alignItems:"center", gap:14 }}>
          <div style={{
            width:64, height:64, borderRadius:14,
            background: ICON_COLORS[draft.iconColor].bg,
            color: ICON_COLORS[draft.iconColor].fg,
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:28, fontWeight:700, fontFamily:"'Source Serif 4', Georgia, serif",
          }}>{draft.name?.[0]?.toUpperCase() || "A"}</div>
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            <div style={{ display:"flex", gap:6 }}>
              {Object.keys(ICON_COLORS).map(c => (
                <button key={c} onClick={()=>update("iconColor", c)} style={{
                  width:22, height:22, borderRadius:6, padding:0,
                  background: ICON_COLORS[c].bg,
                  border: draft.iconColor === c ? `2px solid ${theme.text}` : `1px solid ${theme.cardBorder}`,
                  cursor:"pointer",
                }}/>
              ))}
            </div>
            <button style={{ background:"none", border:`1px solid ${theme.cardBorder}`, padding:"5px 11px", borderRadius:6, fontSize:11.5, fontFamily:"inherit", cursor:"pointer", color: theme.textMuted, alignSelf:"flex-start" }}>{t.pub_choose_file}</button>
          </div>
        </div>
      </PubField>

      <PubField label={t.pub_tags} hint={t.pub_tags_hint} required>
        <div style={{ border:`1px solid ${theme.cardBorder}`, borderRadius:8, padding:8, background: theme.cardBg, display:"flex", flexWrap:"wrap", gap:6, alignItems:"center", minHeight:42 }}>
          {draft.tags.map(tg => (
            <span key={tg} style={{
              display:"inline-flex", alignItems:"center", gap:5, padding:"4px 4px 4px 10px", borderRadius:6,
              background: `${theme.accent}14`, color: theme.accent, fontSize:12, fontWeight:600,
              fontFamily:"ui-monospace, SFMono-Regular, monospace",
            }}>
              {tg}
              <button onClick={()=>removeTag(tg)} style={{ background:"none", border:"none", padding:"2px 4px", cursor:"pointer", color: theme.accent, display:"inline-flex" }}><Icon name="close" size={10} color={theme.accent}/></button>
            </span>
          ))}
          <input value={tagInput} onChange={(e)=>setTagInput(e.target.value)} onKeyDown={(e)=>{ if(e.key==="Enter"){e.preventDefault();addTag();} else if(e.key==="Backspace"&&!tagInput&&draft.tags.length){removeTag(draft.tags[draft.tags.length-1]);} }} placeholder={t.pub_tags_ph} style={{ flex:1, minWidth:120, border:"none", outline:"none", background:"transparent", color: theme.text, fontSize:13, fontFamily:"inherit", padding:"4px 6px" }}/>
        </div>
        {suggestedTags.length > 0 && (
          <div style={{ display:"flex", flexWrap:"wrap", gap:5, marginTop:6 }}>
            {suggestedTags.slice(0, 6).map(tg => (
              <button key={tg} onClick={()=>update("tags", [...draft.tags, tg])} style={{
                padding:"3px 8px", borderRadius:5, border:`1px dashed ${theme.cardBorder}`, background:"transparent",
                fontSize:11, color: theme.textMuted, fontFamily:"ui-monospace, monospace", cursor:"pointer",
              }}>+ {tg}</button>
            ))}
          </div>
        )}
      </PubField>

      <PubField label={t.pub_dept} hint={t.pub_dept_hint} required>
        <div style={{ position:"relative" }}>
          <button onClick={()=>setDeptOpen(o=>!o)} style={{
            width:"100%", padding:"9px 12px", borderRadius:8, border:`1px solid ${theme.cardBorder}`,
            background: theme.cardBg, color: theme.text, fontSize:13, fontFamily:"inherit", cursor:"pointer",
            display:"flex", alignItems:"center", justifyContent:"space-between", gap:10,
          }}>
            <span style={{ display:"inline-flex", alignItems:"center", gap:8 }}>
              <Icon name="building" size={14} color={theme.textMuted}/>
              <span>{deptPath(draft.dept, lang).join(" / ")}</span>
            </span>
            <Icon name="chevronDown" size={12} color={theme.textMuted}/>
          </button>
          {deptOpen && (
            <div style={{ position:"absolute", top:"calc(100% + 4px)", left:0, right:0, background: theme.cardBg, border:`1px solid ${theme.cardBorder}`, borderRadius:8, boxShadow:"0 8px 24px rgba(0,0,0,0.08)", maxHeight:260, overflow:"auto", zIndex:10, padding:6 }}>
              {DEPARTMENTS.flatMap(d1 => [
                { id:d1.id, name: d1[lang==="zh"?"nameZh":"name"], depth:0 },
                ...((d1.children||[]).flatMap(d2 => [
                  { id:d2.id, name: d2[lang==="zh"?"nameZh":"name"], depth:1 },
                  ...((d2.children||[]).map(d3 => ({ id:d3.id, name: d3[lang==="zh"?"nameZh":"name"], depth:2 }))),
                ])),
              ]).map(d => (
                <button key={d.id} onClick={()=>{ update("dept", d.id); setDeptOpen(false); }} style={{
                  display:"flex", alignItems:"center", width:"100%", textAlign:"left",
                  padding:"6px 10px", paddingLeft: 10 + d.depth*16,
                  background: draft.dept === d.id ? `${theme.accent}14` : "transparent",
                  color: draft.dept === d.id ? theme.accent : theme.text,
                  border:"none", borderRadius:5, fontSize:12.5, fontFamily:"inherit", cursor:"pointer", fontWeight: draft.dept===d.id?600:400,
                }}>{d.name}</button>
              ))}
            </div>
          )}
        </div>
      </PubField>

      <PubField label={t.pub_readme} hint={t.pub_readme_hint} required>
        <PubInput value={draft.readme} onChange={(v)=>update("readme", v)} placeholder={t.pub_readme_ph} mono multiline rows={8} theme={theme}/>
      </PubField>

      <PubField label={t.pub_perms} hint={t.pub_perms_hint}>
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          {[
            { k:"network", label:t.detail_perm_network },
            { k:"files",   label:t.detail_perm_files },
            { k:"runtime", label:t.detail_perm_runtime },
            { k:"data",    label:t.detail_perm_data },
          ].map(p => {
            const on = draft.perms[p.k];
            return (
              <button key={p.k} onClick={()=>update("perms", { ...draft.perms, [p.k]: !on })} style={{
                display:"flex", alignItems:"center", gap:10, padding:"8px 11px", borderRadius:7,
                border:`1px solid ${on ? theme.accent : theme.cardBorder}`,
                background: on ? `${theme.accent}0a` : "transparent",
                cursor:"pointer", fontFamily:"inherit", textAlign:"left",
              }}>
                <span style={{ width:16, height:16, borderRadius:4, border:`1.5px solid ${on ? theme.accent : theme.cardBorder}`, background: on ? theme.accent : "transparent", display:"inline-flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                  {on && <Icon name="check" size={11} color={theme.accentFg}/>}
                </span>
                <span style={{ fontSize:12.5, color: theme.text }}>{p.label}</span>
              </button>
            );
          })}
        </div>
      </PubField>
    </div>
  );
}

function ReviewStep({ draft, lang, t, theme, onJump }) {
  const willAutoPublish = draft.scope === "personal";
  const summaryRow = (label, value, stepIdx) => (
    <div style={{ display:"grid", gridTemplateColumns:"140px 1fr auto", gap:14, alignItems:"start", padding:"10px 0", borderTop:`1px solid ${theme.cardBorder}` }}>
      <div style={{ fontSize:12, color: theme.textMuted, fontWeight:500 }}>{label}</div>
      <div style={{ fontSize:13, color: theme.text }}>{value || <span style={{ color:"#bbb", fontStyle:"italic" }}>—</span>}</div>
      <button onClick={()=>onJump(stepIdx)} style={{ background:"none", border:"none", color: theme.accent, fontSize:11.5, fontWeight:600, cursor:"pointer", fontFamily:"inherit" }}>{t.pub_edit}</button>
    </div>
  );
  const sourceText = draft.sourceMethod === "zip" ? (draft.zipName || "—")
    : draft.sourceMethod === "git" ? (draft.gitUrl + (draft.gitBranch ? `  ·  ${draft.gitBranch}` : "")) || "—"
    : (lang==="zh" ? "命令行发布" : "CLI publish");
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:22 }}>
      <div style={{ fontSize:13.5, color: theme.textMuted, lineHeight:1.5 }}>{t.pub_review_intro}</div>

      <div style={{ border:`1px solid ${theme.cardBorder}`, borderRadius:10, padding:"4px 18px", background: theme.cardBg }}>
        <div style={{ padding:"12px 0 8px", fontSize:12, fontWeight:700, color: theme.text, textTransform:"uppercase", letterSpacing:0.6 }}>{t.pub_review_basics}</div>
        {summaryRow(t.pub_name, draft.name, 0)}
        {summaryRow(t.pub_slug, draft.slug, 0)}
        {summaryRow(t.pub_summary, draft.summary, 0)}
        {summaryRow(t.pub_type, t["pub_type_"+draft.type], 0)}
        {summaryRow(t.pub_scope, t["pub_scope_"+draft.scope+"_h"], 0)}
      </div>

      <div style={{ border:`1px solid ${theme.cardBorder}`, borderRadius:10, padding:"4px 18px", background: theme.cardBg }}>
        <div style={{ padding:"12px 0 8px", fontSize:12, fontWeight:700, color: theme.text, textTransform:"uppercase", letterSpacing:0.6 }}>{t.pub_review_source}</div>
        {summaryRow(t.pub_source_method, t["pub_source_"+draft.sourceMethod], 1)}
        {summaryRow(lang==="zh" ? "详情" : "Details", sourceText, 1)}
      </div>

      <div style={{ border:`1px solid ${theme.cardBorder}`, borderRadius:10, padding:"4px 18px", background: theme.cardBg }}>
        <div style={{ padding:"12px 0 8px", fontSize:12, fontWeight:700, color: theme.text, textTransform:"uppercase", letterSpacing:0.6 }}>{t.pub_review_listing}</div>
        {summaryRow(t.pub_tags, draft.tags.join(", "), 2)}
        {summaryRow(t.pub_dept, deptPath(draft.dept, lang).join(" / "), 2)}
        {summaryRow(t.pub_readme, draft.readme ? `${draft.readme.slice(0, 60)}${draft.readme.length>60?"…":""}` : "", 2)}
        {summaryRow(t.pub_perms, Object.entries(draft.perms).filter(([_,v])=>v).map(([k])=>k).join(", ") || (lang==="zh"?"无":"None"), 2)}
      </div>

      <div style={{
        padding:"14px 18px", borderRadius:10,
        background: willAutoPublish ? "oklch(96% 0.03 150)" : "oklch(96% 0.03 75)",
        border: willAutoPublish ? `1px solid oklch(80% 0.08 150)` : `1px solid oklch(82% 0.1 75)`,
        display:"flex", alignItems:"center", gap:12,
      }}>
        <Icon name={willAutoPublish ? "check" : "clock"} size={20} color={willAutoPublish ? "oklch(50% 0.13 150)" : "oklch(50% 0.13 75)"}/>
        <div style={{ display:"flex", flexDirection:"column", gap:2 }}>
          <div style={{ fontSize:12.5, fontWeight:600, color: willAutoPublish ? "oklch(35% 0.13 150)" : "oklch(35% 0.13 75)" }}>{t.pub_review_publish_to}: {t["pub_scope_"+draft.scope+"_h"]}</div>
          <div style={{ fontSize:12, color: willAutoPublish ? "oklch(40% 0.1 150)" : "oklch(40% 0.1 75)" }}>{willAutoPublish ? t.pub_review_status_auto : t.pub_review_status_review}</div>
        </div>
      </div>

      <div style={{ fontSize:11.5, color: theme.textMuted, lineHeight:1.5 }}>
        {t.pub_review_terms} <a href="#" style={{ color: theme.accent, textDecoration:"none" }}>{t.pub_review_terms_link}</a>
      </div>
    </div>
  );
}

function StepContent({ step, draft, setDraft, lang, t, theme, onJump }) {
  if (step === 0) return <BasicsStep draft={draft} setDraft={setDraft} lang={lang} t={t} theme={theme}/>;
  if (step === 1) return <SourceStep draft={draft} setDraft={setDraft} lang={lang} t={t} theme={theme}/>;
  if (step === 2) return <ListingStep draft={draft} setDraft={setDraft} lang={lang} t={t} theme={theme}/>;
  if (step === 3) return <ReviewStep draft={draft} lang={lang} t={t} theme={theme} onJump={onJump}/>;
  return null;
}

