  const typeLabel = t["pub_type_"+draft.type];
  const manifest = JSON.stringify({
    name: draft.slug || "your-extension",

function LivePreview({ draft, lang, t, theme }) {
  const ic = ICON_COLORS[draft.iconColor];
  const typeLabel = t["pub_type_"+draft.type];
  const manifest = JSON.stringify({
    name: draft.slug || "your-extension",
