            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:13, fontWeight:700, color: theme.text, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{draft.name || (lang==="zh" ? "扩展名称" : "Extension name")}</div>
              <div style={{ fontSize:11, color: theme.textMuted, marginTop:2 }}>{typeLabel}</div>
            </div>
          </div>
          <div style={{ fontSize:12, color: theme.textMuted, lineHeight:1.5, minHeight:34 }}>{draft.summary || (lang==="zh" ? "一句话简介将显示在这里。" : "Your one-line description will appear here.")}</div>
          {draft.tags.length > 0 && (
            <div style={{ display:"flex", flexWrap:"wrap", gap:4 }}>
              {draft.tags.slice(0, 4).map(tg => (
