function PublishPage({ lang, t, theme, isDark, cardRadius, density, draft, setDraft, step, setStep, mode, onClose, onSubmitted, onViewListing, onPublishAnother }) {
  // Validate completion of each step
  const stepsValid = [
    !!(draft.name && draft.slug && draft.summary && draft.type && draft.scope),
    draft.sourceMethod === "zip" ? !!draft.zipName : draft.sourceMethod === "git" ? !!draft.gitUrl : true,
    !!(draft.tags.length > 0 && draft.dept && draft.readme),
    true,
  ];
  const canAdvance = stepsValid[step];
  const submit = () => onSubmitted();

  // Success state
  if (step === 4) {
    const willAutoPublish = draft.scope === "personal";
    return (
      <div style={{ maxWidth:520, margin:"80px auto", textAlign:"center", display:"flex", flexDirection:"column", alignItems:"center", gap:18, animation:"fadeIn 0.3s ease" }}>
        <div style={{ width:80, height:80, borderRadius:"50%", background: `${theme.accent}14`, display:"flex", alignItems:"center", justifyContent:"center" }}>
          <Icon name="check" size={40} color={theme.accent}/>
        </div>
        <div className="serif" style={{ fontSize:32, fontWeight:600, letterSpacing:-0.6 }}>{t.pub_success_title}</div>
        <div style={{ fontSize:15, color: theme.textMuted, lineHeight:1.6, maxWidth:400 }}>{willAutoPublish ? t.pub_success_auto : t.pub_success_review}</div>
        <div style={{ display:"flex", gap:10, marginTop:8 }}>
          {willAutoPublish && <button onClick={onViewListing} style={{ padding:"10px 22px", background: theme.accent, color: theme.accentFg, border:"none", borderRadius:8, fontFamily:"inherit", fontSize:13, fontWeight:600, cursor:"pointer" }}>{t.pub_view_listing}</button>}
          <button onClick={onPublishAnother} style={{ padding:"10px 22px", background:"transparent", color: theme.text, border:`1px solid ${theme.cardBorder}`, borderRadius:8, fontFamily:"inherit", fontSize:13, fontWeight:600, cursor:"pointer" }}>{t.pub_publish_another}</button>
          <button onClick={onClose} style={{ padding:"10px 22px", background:"transparent", color: theme.textMuted, border:"none", fontFamily:"inherit", fontSize:13, cursor:"pointer" }}>{t.pub_close}</button>
        </div>
      </div>
    );
  }

  // Header (shared)
  const header = (
    <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:20, marginBottom: mode === "onepage" ? 28 : 24 }}>
      <div>
        <button onClick={onClose} style={{ background:"none", border:"none", color: theme.textMuted, cursor:"pointer", fontSize:12.5, fontFamily:"inherit", padding:"4px 0", display:"inline-flex", alignItems:"center", gap:5, marginBottom:8 }}>
          <Icon name="chevronLeft" size={12} color={theme.textMuted}/> {t.pub_close}
        </button>
        <h1 className="serif" style={{ fontSize:32, fontWeight:600, letterSpacing:-0.7, margin:0, color: theme.text }}>{t.pub_title}</h1>
        <div style={{ fontSize:13.5, color: theme.textMuted, marginTop:6, maxWidth:560, lineHeight:1.55 }}>{t.pub_subtitle}</div>
      </div>
      <button style={{ background:"transparent", border:`1px solid ${theme.cardBorder}`, padding:"7px 13px", borderRadius:7, fontSize:12, fontWeight:600, color: theme.textMuted, cursor:"pointer", fontFamily:"inherit", flexShrink:0 }}>{t.pub_save_draft}</button>
    </div>
  );

  // Footer (back/next)
  const footer = (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:32, paddingTop:20, borderTop:`1px solid ${theme.cardBorder}` }}>
      <div style={{ fontSize:12, color: theme.textMuted }}>{t.pub_step} {step+1} {t.pub_of} {PUB_STEPS.length}</div>
      <div style={{ display:"flex", gap:10 }}>
        <button onClick={()=>setStep(s => Math.max(0, s-1))} disabled={step === 0} style={{
          padding:"9px 18px", borderRadius:7, border:`1px solid ${theme.cardBorder}`, background:"transparent",
          color: step === 0 ? "#ccc" : theme.text, fontFamily:"inherit", fontSize:13, fontWeight:600,
          cursor: step === 0 ? "not-allowed" : "pointer",
        }}>{t.pub_back}</button>
        {step < PUB_STEPS.length - 1 ? (
          <button onClick={()=>canAdvance && setStep(s => s+1)} disabled={!canAdvance} style={{
            padding:"9px 22px", borderRadius:7, border:"none",
            background: canAdvance ? theme.accent : "#ddd", color: canAdvance ? theme.accentFg : "#999",
            fontFamily:"inherit", fontSize:13, fontWeight:600, cursor: canAdvance ? "pointer" : "not-allowed",
          }}>{t.pub_next} →</button>
        ) : (
          <button onClick={submit} style={{
            padding:"9px 22px", borderRadius:7, border:"none",
            background: theme.accent, color: theme.accentFg,
            fontFamily:"inherit", fontSize:13, fontWeight:600, cursor:"pointer",
          }}>{t.pub_publish}</button>
        )}
      </div>
    </div>
  );

  // ─── Mode: Classic top stepper ─────────────────────
  if (mode === "classic") {
    return (
      <div style={{ maxWidth:780, margin:"0 auto", animation:"fadeIn 0.25s ease" }}>
        {header}
        <div style={{ display:"flex", alignItems:"center", gap:0, marginBottom:32, padding:"0 4px" }}>
          {PUB_STEPS.map((sk, i) => {
            const done = i < step;
            const active = i === step;
            const valid = stepsValid[i];
            return (
              <React.Fragment key={sk}>
                <button onClick={()=>i <= step && setStep(i)} disabled={i > step} style={{
                  display:"flex", alignItems:"center", gap:9, background:"none", border:"none", cursor: i <= step ? "pointer" : "not-allowed",
                  padding:"6px 0", fontFamily:"inherit",
                }}>
                  <span style={{
                    width:26, height:26, borderRadius:"50%", display:"inline-flex", alignItems:"center", justifyContent:"center",
                    background: active ? theme.accent : done ? `${theme.accent}` : theme.cardBg,
                    color: active || done ? theme.accentFg : theme.textMuted,
                    border: active || done ? "none" : `1.5px solid ${theme.cardBorder}`,
                    fontSize:12, fontWeight:700,
                  }}>{done ? <Icon name="check" size={12} color={theme.accentFg}/> : (i+1)}</span>
                  <span style={{ fontSize:13, fontWeight: active ? 700 : 500, color: active ? theme.text : theme.textMuted }}>{t[sk]}</span>
                </button>
                {i < PUB_STEPS.length - 1 && <div style={{ flex:1, height:1.5, background: i < step ? theme.accent : theme.cardBorder, margin:"0 14px" }}/>}
              </React.Fragment>
            );
          })}
        </div>
        <div style={{ background: theme.cardBg, border:`1px solid ${theme.cardBorder}`, borderRadius:14, padding:"28px 32px" }}>
          <StepContent step={step} draft={draft} setDraft={setDraft} lang={lang} t={t} theme={theme} onJump={setStep}/>
          {footer}
        </div>
      </div>
    );
  }

  // ─── Mode: Side-rail with live preview ─────────────────────
  if (mode === "rail") {
    return (
      <div style={{ maxWidth:1200, margin:"0 auto", animation:"fadeIn 0.25s ease" }}>
        {header}
        <div style={{ display:"grid", gridTemplateColumns:"200px 1fr 320px", gap:28, alignItems:"flex-start" }}>
          {/* Step rail */}
          <div style={{ position:"sticky", top:8, display:"flex", flexDirection:"column", gap:4 }}>
            {PUB_STEPS.map((sk, i) => {
              const done = i < step;
              const active = i === step;
              return (
                <button key={sk} onClick={()=>i <= step && setStep(i)} disabled={i > step} style={{
                  display:"flex", alignItems:"flex-start", gap:11, padding:"10px 12px", borderRadius:8,
                  background: active ? `${theme.accent}10` : "transparent",
                  border:"none", cursor: i <= step ? "pointer" : "not-allowed",
                  textAlign:"left", fontFamily:"inherit",
                }}>
                  <span style={{
                    width:22, height:22, borderRadius:"50%", display:"inline-flex", alignItems:"center", justifyContent:"center", flexShrink:0,
                    background: active || done ? theme.accent : "transparent",
                    color: active || done ? theme.accentFg : theme.textMuted,
                    border: active || done ? "none" : `1.5px solid ${theme.cardBorder}`,
                    fontSize:11, fontWeight:700, marginTop:1,
                  }}>{done ? <Icon name="check" size={11} color={theme.accentFg}/> : (i+1)}</span>
                  <div style={{ display:"flex", flexDirection:"column", gap:1, minWidth:0 }}>
                    <span style={{ fontSize:13, fontWeight: active ? 700 : 500, color: active ? theme.text : theme.textMuted }}>{t[sk]}</span>
                    <span style={{ fontSize:11, color: theme.textMuted, lineHeight:1.4 }}>{t[sk.replace("step_","")+"_desc"] || t["pub_"+sk.replace("pub_step_","")+"_desc"]}</span>
                  </div>
                </button>
              );
            })}
          </div>

          {/* Form */}
          <div style={{ background: theme.cardBg, border:`1px solid ${theme.cardBorder}`, borderRadius:14, padding:"28px 32px", minWidth:0 }}>
            <StepContent step={step} draft={draft} setDraft={setDraft} lang={lang} t={t} theme={theme} onJump={setStep}/>
            {footer}
          </div>

          {/* Live preview */}
          <div style={{ position:"sticky", top:8 }}>
            <div style={{ fontSize:12, fontWeight:700, color: theme.textMuted, textTransform:"uppercase", letterSpacing:0.7, marginBottom:12 }}>{t.pub_live_preview}</div>
            <LivePreview draft={draft} lang={lang} t={t} theme={theme}/>
          </div>
        </div>
      </div>
    );
  }

  // ─── Mode: Single-page progressive ─────────────────────
  // (mode === "onepage")
  const sections = [
    { key:"pub_step_basics",  desc:"pub_basics_desc",  valid: stepsValid[0] },
    { key:"pub_step_source",  desc:"pub_source_desc",  valid: stepsValid[1] },
    { key:"pub_step_listing", desc:"pub_listing_desc", valid: stepsValid[2] },
    { key:"pub_step_review",  desc:"pub_review_desc",  valid: stepsValid[3] },
  ];
  const completedCount = stepsValid.slice(0, 3).filter(Boolean).length;
  const allValid = stepsValid.slice(0, 3).every(Boolean);
  return (
    <div style={{ maxWidth:980, margin:"0 auto", animation:"fadeIn 0.25s ease" }}>
      {header}
      <div style={{ display:"grid", gridTemplateColumns:"180px 1fr", gap:32, alignItems:"flex-start" }}>
        <div style={{ position:"sticky", top:8 }}>
          {sections.map((s, i) => (
            <a key={s.key} href={`#pub-section-${i}`} style={{
              display:"flex", alignItems:"center", gap:9, padding:"7px 0", textDecoration:"none",
              color: theme.textMuted, fontSize:12.5,
            }}>
              <span style={{
                width:18, height:18, borderRadius:"50%", display:"inline-flex", alignItems:"center", justifyContent:"center", flexShrink:0,
                background: s.valid ? theme.accent : "transparent",
                border: s.valid ? "none" : `1.5px solid ${theme.cardBorder}`,
              }}>{s.valid && <Icon name="check" size={10} color={theme.accentFg}/>}</span>
              <span style={{ fontWeight: s.valid ? 600 : 500, color: s.valid ? theme.text : theme.textMuted }}>{t[s.key]}</span>
            </a>
          ))}
          <div style={{ marginTop:18, padding:"10px 12px", background: theme.cardBg, borderRadius:8, border:`1px solid ${theme.cardBorder}`, fontSize:11.5, color: theme.textMuted, lineHeight:1.5 }}>
            <div style={{ fontWeight:700, color: theme.text, marginBottom:3 }}>{completedCount}/3 {t.pub_complete}</div>
            <div style={{ height:4, borderRadius:2, background: theme.cardBorder, overflow:"hidden", marginTop:6 }}>
              <div style={{ width:`${(completedCount/3)*100}%`, height:"100%", background: theme.accent, transition:"width 0.3s" }}/>
            </div>
          </div>
        </div>

        <div style={{ display:"flex", flexDirection:"column", gap:18 }}>
          {sections.map((s, i) => (
            <div key={s.key} id={`pub-section-${i}`} style={{ background: theme.cardBg, border:`1px solid ${s.valid ? theme.accent+"40" : theme.cardBorder}`, borderRadius:14, padding:"24px 28px" }}>
