1	"use server";
2	
3	import { and, desc, eq } from "drizzle-orm";
4	import { headers } from "next/headers";
5	
6	import { auth } from "@/lib/auth";
7	import { db } from "@/lib/db/client";
8	import {
9	  extensions,
10	  extensionVersions,
11	  extensionTags,
12	  files,
13	} from "@/lib/db/schema";
14	import { submit, VersionStateError } from "@/lib/extensions/state";
15	import { ManifestFormSchema, type ManifestFormValues } from "@/lib/validators/manifest";
16	
17	import { extractScanReason } from "@/lib/publish/scan-report";
18	
19	import {
20	  classifyDraftError,
21	  devErrorDetail,
22	  pgConstraint,
23	  pgErrorCode,
24	} from "./publish-errors";
25	
26	const DEFAULT_ORG_ID = "default";
27	
28	// Coerce empty / missing optional strings to `null`. We can't use `?? null`
29	// (it keeps `""`, which then FK-violates against `departments.id`) and we
30	// avoid `|| null` because it would also drop a legitimate `"0"`.
31	function emptyToNull(v: string | undefined | null): string | null {
32	  return v == null || v === "" ? null : v;
33	}
34	
35	export type CreateDraftResult =
36	  | { ok: true; extensionId: string; versionId: string }
37	  | { ok: false; error: string; detail?: string };
38	
39	export async function createDraftExtension(
40	  raw: ManifestFormValues,
41	): Promise<CreateDraftResult> {
42	  const session = await auth.api.getSession({ headers: await headers() });
43	  if (!session) return { ok: false, error: "unauthenticated" };
44	
45	  const parsed = ManifestFormSchema.safeParse(raw);
46	  if (!parsed.success) {
47	    // Return a stable error code (so the UI can localize it) and put the
48	    // human-readable Zod messages in `detail` so the user can see *what*
49	    // failed even outside development.
50	    return {
51	      ok: false,
52	      error: "invalid_input",
53	      detail: parsed.error.issues.map((i) => i.message).join("; "),
54	    };
55	  }
56	  const data = parsed.data;
57	
58	  const extensionId = crypto.randomUUID();
59	  const versionId = crypto.randomUUID();
60	
61	  try {
62	    await db.transaction(async (tx) => {
63	      await tx.insert(extensions).values({
64	        id: extensionId,
65	        slug: data.slug,
66	        name: data.name,
67	        nameZh: emptyToNull(data.nameZh),
68	        tagline: emptyToNull(data.tagline),
69	        description: emptyToNull(data.description),
70	        descriptionZh: emptyToNull(data.descriptionZh),
71	        category: data.category,
72	        scope: data.scope,
73	        funcCat: data.funcCat,
74	        subCat: data.subCat,
75	        l2: emptyToNull(data.l2),
76	        // Empty strings are FK violations against departments.id — coerce to null.
77	        deptId: emptyToNull(data.deptId),
78	        homepageUrl: emptyToNull(data.homepageUrl),
79	        repoUrl: emptyToNull(data.repoUrl),
80	        licenseSpdx: emptyToNull(data.licenseSpdx),
81	        publisherUserId: session.user.id,
82	        ownerOrgId: DEFAULT_ORG_ID,
83	        visibility: "draft",
84	      });
85	
86	      await tx.insert(extensionVersions).values({
87	        id: versionId,
88	        extensionId,
89	        version: data.version,
90	        status: "pending",
91	      });
92	
93	      if (data.tagIds.length > 0) {
94	        await tx.insert(extensionTags).values(
95	          data.tagIds.map((tagId) => ({ extensionId, tagId })),
96	        );
97	      }
98	    });
99	  } catch (err) {
100	    const code = classifyDraftError(err);
101	    console.error("[publish] createDraftExtension failed", {
102	      code,
103	      pgCode: pgErrorCode(err),
104	      constraint: pgConstraint(err),
105	      slug: data.slug,
106	      message: err instanceof Error ? err.message : String(err),
107	    });
108	    return { ok: false, error: code, detail: devErrorDetail(err) };
109	  }
110	
111	  return { ok: true, extensionId, versionId };
112	}
113	
114	export type AttachFileResult =
115	  | { ok: true }
116	  | { ok: false; error: string; detail?: string };
117	
118	export async function attachFile(
119	  versionId: string,
120	  r2Key: string,
121	  size: number,
122	  checksumSha256: string,
123	): Promise<AttachFileResult> {
124	  const session = await auth.api.getSession({ headers: await headers() });
125	  if (!session) return { ok: false, error: "unauthenticated" };
126	
127	  const fileId = crypto.randomUUID();
128	
129	  try {
130	    await db.transaction(async (tx) => {
131	      await tx.insert(files).values({
132	        id: fileId,
133	        r2Key,
134	        size: BigInt(size),
135	        checksumSha256,
136	        mimeType: "application/zip",
137	        scanStatus: "pending",
138	      });
139	      await tx
140	        .update(extensionVersions)
141	        .set({ bundleFileId: fileId })
142	        .where(eq(extensionVersions.id, versionId));
143	    });
144	  } catch (err) {
145	    console.error("[publish] attachFile failed", {
146	      pgCode: pgErrorCode(err),
147	      constraint: pgConstraint(err),
148	      versionId,
149	      r2Key,
150	      message: err instanceof Error ? err.message : String(err),
151	    });
152	    return { ok: false, error: "db_error", detail: devErrorDetail(err) };
153	  }
154	
155	  return { ok: true };
156	}
157	
158	export type SubmitResult =
159	  | { ok: true }
160	  | { ok: false; error: string; detail?: string };
161	
162	export async function submitForReview(versionId: string): Promise<SubmitResult> {
163	  const session = await auth.api.getSession({ headers: await headers() });
164	  if (!session) return { ok: false, error: "unauthenticated" };
165	
166	  // Load bundleFileId needed by the scan job
167	  const [version] = await db
168	    .select({ bundleFileId: extensionVersions.bundleFileId })
169	    .from(extensionVersions)
170	    .where(eq(extensionVersions.id, versionId))
171	    .limit(1);
172	
173	  if (!version?.bundleFileId) return { ok: false, error: "no_bundle" };
174	
175	  try {
176	    await submit(versionId);
177	  } catch (err) {
178	    console.error("[publish] submitForReview failed", {
179	      pgCode: pgErrorCode(err),
180	      versionId,
181	      message: err instanceof Error ? err.message : String(err),
182	    });
183	    // The state machine refused the transition — the version isn't in a
184	    // submittable state (already reviewed/rejected, or the row vanished).
185	    // This is not a generic DB error and shouldn't be reported as one.
186	    if (err instanceof VersionStateError) {
187	      return {
188	        ok: false,
189	        error: "version_not_submittable",
190	        detail: devErrorDetail(err),
191	      };
192	    }
193	    return { ok: false, error: "db_error", detail: devErrorDetail(err) };
194	  }
195	
196	  // Queue the scan job. If this fails (e.g. INNGEST_EVENT_KEY missing,
197	  // Inngest unreachable), roll the version status back to `pending` so it
198	  // doesn't sit stuck in `scanning` with no scan ever happening.
199	  try {
200	    const { inngest } = await import("@/lib/jobs/client");
201	    await inngest.send({
202	      name: "extension/scan.requested",
203	      data: { versionId, fileId: version.bundleFileId },
204	    });
205	  } catch (err) {
206	    console.error("[publish] inngest.send failed", err);
207	    try {
208	      await db
209	        .update(extensionVersions)
210	        .set({ status: "pending" })
211	        .where(
212	          and(
213	            eq(extensionVersions.id, versionId),
214	            eq(extensionVersions.status, "scanning"),
215	          ),
216	        );
217	    } catch (rollbackErr) {
218	      console.error(
219	        "[publish] failed to roll back scanning -> pending after inngest error",
220	        rollbackErr,
221	      );
222	    }
223	    return {
224	      ok: false,
225	      error: "scan_queue_unavailable",
226	      detail: devErrorDetail(err),
227	    };
228	  }
229	
230	  return { ok: true };
231	}
232	
233	export async function getMyExtensions(userId: string) {
234	  // Pull the latest version per extension alongside the extension row so the
235	  // dashboard can show "where am I in the wizard" (e.g. needs upload vs.
236	  // submitted, awaiting scan) — visibility alone hides that info. Also
237	  // joins the bundle file via `bundleFileId` (logical reference, no FK)
238	  // so the dashboard can surface the scan rejection reason inline for
239	  // rejected versions without an extra round-trip.
240	  const rows = await db
241	    .select({
242	      id: extensions.id,
243	      slug: extensions.slug,
244	      name: extensions.name,
245	      category: extensions.category,
246	      visibility: extensions.visibility,
247	      createdAt: extensions.createdAt,
248	      latestVersionId: extensionVersions.id,
249	      latestVersion: extensionVersions.version,
250	      latestStatus: extensionVersions.status,
251	      latestBundleFileId: extensionVersions.bundleFileId,
252	      latestScanReport: files.scanReport,
253	    })
254	    .from(extensions)
255	    .leftJoin(
256	      extensionVersions,
257	      eq(extensionVersions.extensionId, extensions.id),
258	    )
259	    .leftJoin(files, eq(files.id, extensionVersions.bundleFileId))
260	    .where(eq(extensions.publisherUserId, userId))
261	    .orderBy(desc(extensions.createdAt), desc(extensionVersions.createdAt));
262	
263	  // Collapse to one row per extension (latest version first thanks to the
264	  // ORDER BY). If we someday support multiple in-flight versions per
265	  // extension, this becomes a `DISTINCT ON` query.
266	  const byExtension = new Map<
267	    string,
268	    (typeof rows)[number] & { latestScanReason: string | null }
269	  >();
270	  for (const row of rows) {
271	    if (!byExtension.has(row.id)) {
272	      byExtension.set(row.id, {
273	        ...row,
274	        latestScanReason: extractScanReason(row.latestScanReport),
275	      });
276	    }
277	  }
278	  return Array.from(byExtension.values());
279	}
280	
281	export type UpdateDraftResult =
282	  | { ok: true }
283	  | { ok: false; error: string; detail?: string };
284	
285	// Update an in-flight draft's manifest fields. Owner-checked. Refuses to
286	// touch anything once the version has left `pending` — by then the
287	// scanner has likely picked it up and re-running scans is the worker's
288	// job, not the wizard's. `slug` and `version` can technically be
289	// changed, but the wizard locks them in resume mode because they form
290	// the R2 bundle key — letting them shift orphans the uploaded bundle.
291	export async function updateDraftExtension(
292	  extensionId: string,
293	  raw: ManifestFormValues,
294	): Promise<UpdateDraftResult> {
295	  const session = await auth.api.getSession({ headers: await headers() });
296	  if (!session) return { ok: false, error: "unauthenticated" };
297	
298	  const parsed = ManifestFormSchema.safeParse(raw);
299	  if (!parsed.success) {
300	    return {
301	      ok: false,
302	      error: "invalid_input",
303	      detail: parsed.error.issues.map((i) => i.message).join("; "),
304	    };
305	  }
306	  const data = parsed.data;
307	
308	  // Resolve the latest version + verify ownership + state in one read.
309	  const [row] = await db
310	    .select({
311	      publisherUserId: extensions.publisherUserId,
312	      versionId: extensionVersions.id,
313	      versionStatus: extensionVersions.status,
314	    })
315	    .from(extensions)
316	    .leftJoin(
317	      extensionVersions,
318	      eq(extensionVersions.extensionId, extensions.id),
319	    )
320	    .where(eq(extensions.id, extensionId))
321	    .orderBy(desc(extensionVersions.createdAt))
322	    .limit(1);
323	
324	  if (!row || !row.versionId) {
325	    return { ok: false, error: "not_found" };
326	  }
327	  if (row.publisherUserId !== session.user.id) {
328	    return { ok: false, error: "not_found" };
329	  }
330	  if (row.versionStatus !== "pending") {
331	    return { ok: false, error: "version_not_editable" };
332	  }
333	
334	  try {
335	    await db.transaction(async (tx) => {
336	      // SECURITY: `slug` and `version` are deliberately NOT written from
337	      // `data`. The wizard renders those inputs as `readOnly` in resume
338	      // mode, but `readOnly` is a client-side hint only — a caller
339	      // hitting this action directly (devtools, scripted POST) could
340	      // otherwise change the slug or version, which would orphan the
341	      // already-uploaded R2 bundle at its old `<slug>/<version>` key.
342	      // Rejecting mismatches outright would also work; silently keeping
343	      // the stored values is the smaller-surface choice and keeps the
344	      // resume flow forgiving when the form round-trips its locked
345	      // values back unchanged.
346	      await tx
347	        .update(extensions)
348	        .set({
349	          name: data.name,
350	          nameZh: emptyToNull(data.nameZh),
351	          tagline: emptyToNull(data.tagline),
352	          description: emptyToNull(data.description),
353	          descriptionZh: emptyToNull(data.descriptionZh),
354	          category: data.category,
355	          scope: data.scope,
356	          funcCat: data.funcCat,
357	          subCat: data.subCat,
358	          l2: emptyToNull(data.l2),
359	          deptId: emptyToNull(data.deptId),
360	          homepageUrl: emptyToNull(data.homepageUrl),
361	          repoUrl: emptyToNull(data.repoUrl),
362	          licenseSpdx: emptyToNull(data.licenseSpdx),
363	          updatedAt: new Date(),
364	        })
365	        .where(eq(extensions.id, extensionId));
366	
367	      // Tags: replace wholesale. The set is capped at 8 by the form
368	      // schema, so a delete-then-insert is cheaper and clearer than
369	      // computing a diff.
370	      await tx
371	        .delete(extensionTags)
372	        .where(eq(extensionTags.extensionId, extensionId));
373	      if (data.tagIds.length > 0) {
374	        await tx
375	          .insert(extensionTags)
376	          .values(data.tagIds.map((tagId) => ({ extensionId, tagId })));
377	      }
378	    });
379	  } catch (err) {
380	    const code = classifyDraftError(err);
381	    console.error("[publish] updateDraftExtension failed", {
382	      code,
383	      pgCode: pgErrorCode(err),
384	      constraint: pgConstraint(err),
385	      extensionId,
386	      message: err instanceof Error ? err.message : String(err),
387	    });
388	    return { ok: false, error: code, detail: devErrorDetail(err) };
389	  }
390	
391	  return { ok: true };
392	}
393	
394	export type DiscardDraftResult =
395	  | { ok: true }
396	  | { ok: false; error: "not_found" | "unauthenticated" | "not_discardable" };
397	
398	// Permanently delete a draft extension. Owner-checked. Only allowed while
399	// visibility === "draft" — published or archived extensions are not
400	// throwaway. Cascading FK constraints clean up extension_versions,
401	// extension_tags, and (via versions) any associated files row.
402	//
403	// R2 bundle objects are intentionally left in place; orphan cleanup is
404	// the bucket lifecycle's job, not the user's.
405	export async function discardDraft(
406	  extensionId: string,
407	): Promise<DiscardDraftResult> {
408	  const session = await auth.api.getSession({ headers: await headers() });
409	  if (!session) return { ok: false, error: "unauthenticated" };
410	
411	  const [row] = await db
412	    .select({
413	      publisherUserId: extensions.publisherUserId,
414	      visibility: extensions.visibility,
415	    })
416	    .from(extensions)
417	    .where(eq(extensions.id, extensionId))
418	    .limit(1);
419	
420	  // Treat not-found and not-owner identically so the contract can't be
421	  // used to probe whether an extension exists for someone else.
422	  if (!row || row.publisherUserId !== session.user.id) {
423	    return { ok: false, error: "not_found" };
424	  }
425	  if (row.visibility !== "draft") {
426	    return { ok: false, error: "not_discardable" };
427	  }
428	
429	  await db.delete(extensions).where(eq(extensions.id, extensionId));
430	  return { ok: true };
431	}
432	
433	export async function getVersionStatus(versionId: string) {
434	  const [row] = await db
435	    .select({ status: extensionVersions.status })
436	    .from(extensionVersions)
437	    .where(eq(extensionVersions.id, versionId))
438	    .limit(1);
439	  return row?.status ?? null;
440	}
441	
442	export type DraftSnapshot = {
443	  extensionId: string;
444	  versionId: string;
445	  slug: string;
446	  version: string;
447	  name: string;
448	  category: string;
449	  visibility: string;
450	  versionStatus: string;
451	  bundleUploaded: boolean;
452	  // Full manifest values for the form pre-fill in edit mode. Loaded by
453	  // `getDraft` regardless of state since the dashboard never shows them
454	  // — only the resume page reads this. Tag IDs come from a sibling
455	  // query against `extension_tags`.
456	  formValues: ManifestFormValues;
457	};
458	
459	export type GetDraftResult =
460	  | { ok: true; draft: DraftSnapshot }
461	  // Deliberately collapse non-owner to `not_found` so the public contract
462	  // can't be used to probe whether an extension exists for someone else's
463	  // account.
464	  | { ok: false; error: "not_found" | "unauthenticated" };
465	
466	// Load an extension + its latest version for the publish wizard's resume
467	// flow. Owner-checked: callers cannot read another user's draft. Returns
468	// just enough state for the wizard to land on the right step and render
469	// a read-only manifest summary.
470	export async function getDraft(extensionId: string): Promise<GetDraftResult> {
471	  const session = await auth.api.getSession({ headers: await headers() });
472	  if (!session) return { ok: false, error: "unauthenticated" };
473	
474	  const [row] = await db
475	    .select({
476	      extensionId: extensions.id,
477	      publisherUserId: extensions.publisherUserId,
478	      slug: extensions.slug,
479	      name: extensions.name,
480	      nameZh: extensions.nameZh,
481	      tagline: extensions.tagline,
482	      description: extensions.description,
483	      descriptionZh: extensions.descriptionZh,
484	      category: extensions.category,
485	      scope: extensions.scope,
486	      funcCat: extensions.funcCat,
487	      subCat: extensions.subCat,
488	      l2: extensions.l2,
489	      deptId: extensions.deptId,
490	      homepageUrl: extensions.homepageUrl,
491	      repoUrl: extensions.repoUrl,
492	      licenseSpdx: extensions.licenseSpdx,
493	      visibility: extensions.visibility,
494	      versionId: extensionVersions.id,
495	      version: extensionVersions.version,
496	      versionStatus: extensionVersions.status,
497	      bundleFileId: extensionVersions.bundleFileId,
498	    })
499	    .from(extensions)
500	    .leftJoin(
501	      extensionVersions,
502	      eq(extensionVersions.extensionId, extensions.id),
503	    )
504	    .where(eq(extensions.id, extensionId))
505	    .orderBy(desc(extensionVersions.createdAt))
506	    .limit(1);
507	
508	  if (!row || !row.versionId || !row.version || !row.versionStatus) {
509	    return { ok: false, error: "not_found" };
510	  }
511	  if (row.publisherUserId !== session.user.id) {
512	    // Same shape as a missing row; see comment on `GetDraftResult`.
513	    return { ok: false, error: "not_found" };
514	  }
515	
516	  // Tag IDs in a separate, very small query — extensions cap tags at 8
517	  // per the form schema, so this is at most 8 rows.
518	  const tagRows = await db
519	    .select({ tagId: extensionTags.tagId })
520	    .from(extensionTags)
521	    .where(eq(extensionTags.extensionId, row.extensionId));
522	  const tagIds = tagRows.map((r) => r.tagId);
523	
524	  return {
525	    ok: true,
526	    draft: {
527	      extensionId: row.extensionId,
528	      versionId: row.versionId,
529	      slug: row.slug,
530	      version: row.version,
531	      name: row.name,
532	      category: row.category,
533	      visibility: row.visibility,
534	      versionStatus: row.versionStatus,
535	      bundleUploaded: row.bundleFileId !== null,
536	      formValues: {
537	        slug: row.slug,
538	        name: row.name,
539	        nameZh: row.nameZh ?? "",
540	        version: row.version,
541	        category: row.category as ManifestFormValues["category"],
542	        scope: row.scope as ManifestFormValues["scope"],
543	        funcCat: row.funcCat as ManifestFormValues["funcCat"],
544	        subCat: row.subCat,
545	        l2: row.l2 ?? "",
546	        deptId: row.deptId ?? "",
547	        tagIds,
548	        description: row.description ?? "",
549	        descriptionZh: row.descriptionZh ?? "",
550	        tagline: row.tagline ?? "",
551	        homepageUrl: row.homepageUrl ?? "",
552	        repoUrl: row.repoUrl ?? "",
553	        licenseSpdx: row.licenseSpdx ?? "",
554	      },
555	    },
556	  };
557	}
