      tagline: "A great skill",
      descriptionZh: "做事情。",
      homepageUrl: "https://example.com",
      repoUrl: "https://github.com/foo/bar",
      licenseSpdx: "MIT",
      l2: "backend",
      deptId: "eng.cloud",
      tagIds: ["search", "api"],
