  const attempted = {
    ...validValues,
    slug: "hijacked-slug",
    version: "9.9.9",
  };
  const result = await updateDraftExtension("ext-1", attempted);
  expect(result).toEqual({ ok: true });

  // The wizard issues two patches: one against `extensions` (no slug,
