85	  const [draft, setDraft] = useState<DraftState | null>(
86	    resume
87	      ? {
88	          extensionId: resume.extensionId,
89	          versionId: resume.versionId,
90	          slug: resume.slug,
91	          version: resume.version,
92	        }
93	      : null,
