96	  const [submitting, setSubmitting] = useState(false);
97	  const [submitted, setSubmitted] = useState(false);
98	  const [error, setError] = useState<string | null>(null);
99	  const [errorDetail, setErrorDetail] = useState<string | null>(null);
100	  const [uploadProgress, setUploadProgress] = useState<"idle" | "uploading" | "done">(
