  versionId: string;
  slug: string;
  version: string;
  name: string;
  category: string;
  scope: string;
  bundleUploaded: boolean;
  formValues: ManifestFormValues;
}

const EMPTY_DRAFT: ManifestFormValues = {
  slug: "",
  name: "",
  nameZh: "",
  version: "1.0.0",
  category: "skills",
  scope: "personal",
  summary: "",
  taglineZh: "",
  readmeMd: "",
  iconColor: "indigo",
  tagIds: [],
  deptId: "",
  permissions: {},
  sourceMethod: "zip",
