    setBusy(true);
    try {
      if (extensionId) {
        const result = await updateDraftExtension(extensionId, draft);
        if (!result.ok) {
          reportError(describeError(result.error), result.detail ?? null);
          return;
        }
      } else {
        const result = await createDraftExtension(draft);
        if (!result.ok) {
          reportError(describeError(result.error), result.detail ?? null);
          return;
        }
        setExtensionId(result.extensionId);
        setVersionId(result.versionId);
      }
      setStep(1);
    } finally {
      setBusy(false);
    }
  }

  async function saveDraft() {
    clearError();
    setBusy(true);
    try {
      if (extensionId) {
        const result = await updateDraftExtension(extensionId, draft);
        if (!result.ok) {
          reportError(describeError(result.error), result.detail ?? null);
          return;
        }
      } else if (stepsValid[0]) {
        const result = await createDraftExtension(draft);
        if (!result.ok) {
          reportError(describeError(result.error), result.detail ?? null);
          return;
        }
